s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']
    
    try:
        # Read image from S3
        response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
        image_content = response['Body'].read()
        
        # Process the image (this is a placeholder for image processing logic)
        processed_image = image_content  # Replace with actual processing
        
        # Write results back to S3
        output_key = f'processed/{object_key}'
        s3_client.put_object(Bucket=bucket_name, Key=output_key, Body=processed_image)
        
        # Send notification via SNS
        sns_topic_arn = 'arn:aws:sns:region:account-id:topic-name'
        sns_client.publish(
            TopicArn=sns_topic_arn,
            Message=json.dumps({'image_key': output_key}),
            Subject='Image Processing Completed'
        )
        
        logger.info(f'Processed image saved to {output_key} and notification sent.')

    except Exception as e:
        logger.error(f'Error processing image: {str(e)}')